package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithRecordSeparator_char() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\n';

        CSVFormat result = original.withRecordSeparator(separator);

        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
    }

    @Test
    void testWithRecordSeparator_char_differentSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\r';

        CSVFormat result = original.withRecordSeparator(separator);

        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
    }

    @Test
    void testWithRecordSeparator_char_edgeCases() {
        CSVFormat original = CSVFormat.DEFAULT;

        // Test with tab character
        char separatorTab = '\t';
        CSVFormat resultTab = original.withRecordSeparator(separatorTab);
        assertEquals(String.valueOf(separatorTab), resultTab.getRecordSeparator());

        // Test with space character
        char separatorSpace = ' ';
        CSVFormat resultSpace = original.withRecordSeparator(separatorSpace);
        assertEquals(String.valueOf(separatorSpace), resultSpace.getRecordSeparator());

        // Test with special character
        char separatorSpecial = '\u2028'; // line separator unicode char
        CSVFormat resultSpecial = original.withRecordSeparator(separatorSpecial);
        assertEquals(String.valueOf(separatorSpecial), resultSpecial.getRecordSeparator());
    }
}
